import {
  Observable, of, from, interval, timer, fromEvent, EMPTY, NEVER
} from 'rxjs';
import { take, map } from 'rxjs/operators';

// ── of() — emit a fixed set of values, then complete ────────
const numbers$ = of(1, 2, 3, 4, 5);
numbers$.subscribe({
  next: v     => console.log('next:', v),   // 1, 2, 3, 4, 5
  complete: () => console.log('done'),       // done
});

// ── from() — convert array, Promise, or iterable ───────────
const fromArray$   = from([10, 20, 30]);       // emits 10, 20, 30
const fromPromise$ = from(fetch('/api/user')); // wraps a Promise
const fromMap$     = from(new Map([['a', 1], ['b', 2]]));

// ── interval() — emit 0,1,2,3... every N ms ─────────────────
const tick$ = interval(1000).pipe(take(5)); // 0,1,2,3,4 then complete

// ── timer() — emit once after delay, OR every N ms after delay
const delay$  = timer(3000);           // emit 0 after 3s, then complete
const repeat$ = timer(1000, 500);      // after 1s start emitting every 500ms

// ── fromEvent() — DOM events as a stream ────────────────────
const clicks$ = fromEvent<MouseEvent>(document, 'click');
const keys$   = fromEvent<KeyboardEvent>(document, 'keydown').pipe(
  map(e => e.key)
);

// ── new Observable() — full manual control ──────────────────
const custom$ = new Observable<number>(subscriber => {
  subscriber.next(1);
  subscriber.next(2);
  const id = setTimeout(() => {
    subscriber.next(3);
    subscriber.complete();  // marks the stream as finished
  }, 1000);

  // Teardown logic — runs when unsubscribed or stream ends
  return () => clearTimeout(id);
});

// ── EMPTY — completes immediately without emitting ──────────
// EMPTY.subscribe({ complete: () => console.log('empty!') });

// Subscribing — three patterns, same result:
const sub1 = numbers$.subscribe(v => console.log(v));     // shorthand
const sub2 = numbers$.subscribe({ next: v => console.log(v) }); // observer
sub1.unsubscribe(); // cancel manually

import { of, fromEvent } from 'rxjs';
import {
  map, filter, tap, scan, take, distinctUntilChanged, debounceTime
} from 'rxjs/operators';

// ── map() — transform every value ────────────────────────────
of(1, 2, 3, 4, 5).pipe(
  map(n => n * n)   // 1, 4, 9, 16, 25
).subscribe(console.log);

// ── filter() — only pass matching values ─────────────────────
of(1, 2, 3, 4, 5, 6).pipe(
  filter(n => n % 2 === 0)  // 2, 4, 6
).subscribe(console.log);

// ── tap() — side effects without changing the stream ─────────
of(1, 2, 3).pipe(
  tap(n => console.log('before map:', n)),   // log original
  map(n => n * 10),
  tap(n => console.log('after map:', n)),    // log transformed
).subscribe();

// ── scan() — running accumulator (like reduce but streaming) ──
of(1, 2, 3, 4, 5).pipe(
  scan((acc, n) => acc + n, 0)  // 1, 3, 6, 10, 15
).subscribe(console.log);

// ── Real-world: search input with debounce ────────────────────
const searchInput = document.querySelector<HTMLInputElement>('#search')!;

fromEvent(searchInput, 'input').pipe(
  map(e => (e.target as HTMLInputElement).value.trim()),
  filter(q => q.length >= 2),          // skip short queries
  debounceTime(300),                   // wait 300ms of silence
  distinctUntilChanged(),              // skip if query didn't change
  tap(q => console.log('Searching for:', q))
).subscribe(q => {
  // call API with q
});

// ── take() — limit emissions ──────────────────────────────────
of(1, 2, 3, 4, 5).pipe(
  take(3)   // 1, 2, 3 — then completes
).subscribe(console.log);

import { Component, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { FormControl, ReactiveFormsModule } from '@angular/forms';
import { toSignal } from '@angular/core/rxjs-interop';
import {
  switchMap, concatMap, exhaustMap, mergeMap,
  debounceTime, distinctUntilChanged, catchError, of, Subject
} from 'rxjs';

@Component({ standalone: true, imports: [ReactiveFormsModule], template: '' })
export class OperatorsDemo {
  private http = inject(HttpClient);

  searchCtrl = new FormControl('');
  saveClick$ = new Subject<void>();
  refreshClick$ = new Subject<void>();

  // ── switchMap: search-as-you-type ────────────────────────
  // When user types fast, each keystroke cancels the previous HTTP request
  // Only the result for the LATEST query is shown
  searchResults$ = this.searchCtrl.valueChanges.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap(query =>
      query
        ? this.http.get<any[]>(`/api/search?q=${query}`).pipe(
            catchError(() => of([]))  // return empty on error
          )
        : of([])
    )
  );

  // ── exhaustMap: prevent duplicate form submissions ────────
  // If user clicks 'Save' while a save is already in progress,
  // the second click is IGNORED until the first completes
  saveResult$ = this.saveClick$.pipe(
    exhaustMap(() =>
      this.http.post('/api/save', { data: 'payload' }).pipe(
        catchError(err => of({ error: err.message }))
      )
    )
  );

  // ── concatMap: process a queue of uploads in order ────────
  // Files are uploaded one-by-one in the order they were queued
  // Each upload waits for the previous to complete
  uploadFile(files: File[]): void {
    of(...files).pipe(
      concatMap(file => this.uploadSingle(file))
    ).subscribe(result => console.log('Uploaded:', result));
  }

  // ── mergeMap: send independent notifications in parallel ───
  // All 3 requests fire simultaneously, results arrive in any order
  sendNotifications(userIds: string[]): void {
    of(...userIds).pipe(
      mergeMap(id => this.http.post(`/api/notify/${id}`, {}))
    ).subscribe();
  }

  private uploadSingle(file: File) {
    const fd = new FormData();
    fd.append('file', file);
    return this.http.post('/api/upload', fd);
  }
}

import { Injectable, signal, computed } from '@angular/core';
import { Subject, BehaviorSubject, ReplaySubject } from 'rxjs';
import { map } from 'rxjs/operators';

// ── Subject — live multicast, no history ─────────────────────
const events$ = new Subject<string>();

events$.subscribe(e => console.log('Subscriber A:', e));
events$.next('login');    // → Subscriber A: login
events$.next('navigate'); // → Subscriber A: navigate

events$.subscribe(e => console.log('Subscriber B:', e)); // joins late
events$.next('logout');   // → Subscriber A: logout, Subscriber B: logout
// Subscriber B MISSED 'login' and 'navigate'


// ── BehaviorSubject — holds latest value, replays to newcomers
const theme$ = new BehaviorSubject<'light' | 'dark'>('light');

theme$.subscribe(t => console.log('Component A theme:', t)); // 'light' immediately
theme$.next('dark');
theme$.subscribe(t => console.log('Component B theme:', t)); // 'dark' immediately
// Component B got the CURRENT value even though it subscribed after the change

console.log('Current theme:', theme$.getValue()); // synchronous read: 'dark'


// ── Real-world: Notification service using Subject ────────────
@Injectable({ providedIn: 'root' })
export class NotificationService {
  private _notify$ = new Subject<{ message: string; type: 'success' | 'error' }>();
  readonly notify$ = this._notify$.asObservable(); // expose read-only

  success(message: string): void { this._notify$.next({ message, type: 'success' }); }
  error(message: string):   void { this._notify$.next({ message, type: 'error' }); }
}


// ── Real-world: Shared state service using BehaviorSubject ────
@Injectable({ providedIn: 'root' })
export class CartService {
  private items$ = new BehaviorSubject<{ id: number; name: string }[]>([]);

  readonly cart$       = this.items$.asObservable();
  readonly itemCount$  = this.items$.pipe(map(items => items.length));
  readonly isEmpty$    = this.items$.pipe(map(items => items.length === 0));

  addItem(item: { id: number; name: string }): void {
    this.items$.next([...this.items$.getValue(), item]);
  }

  removeItem(id: number): void {
    this.items$.next(this.items$.getValue().filter(i => i.id !== id));
  }

  clear(): void {
    this.items$.next([]);
  }
}

import { Component, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import {
  catchError, retry, throwError, EMPTY, of, timer
} from 'rxjs';
import { switchMap } from 'rxjs/operators';

@Component({ standalone: true, template: '' })
export class ErrorHandlingDemo {
  private http = inject(HttpClient);

  // ── catchError: return fallback value ────────────────────
  posts$ = this.http.get<any[]>('/api/posts').pipe(
    catchError(err => {
      console.error('Failed to load posts:', err.status);
      return of([]);  // return empty array as fallback
    })
  );

  // ── retry(n): try up to 3 times before failing ────────────
  userData$ = this.http.get('/api/user').pipe(
    retry(3),          // retry 3 times on error
    catchError(err => throwError(() => new Error('User load failed: ' + err.message)))
  );

  // ── retry with exponential backoff ───────────────────────
  criticalData$ = this.http.get('/api/critical').pipe(
    retry({
      count: 3,
      delay: (error, retryCount) => {
        console.log(`Retry attempt ${retryCount} after error:`, error.status);
        return timer(1000 * Math.pow(2, retryCount - 1)); // 1s, 2s, 4s
      }
    }),
    catchError(err => {
      console.error('All retries failed:', err);
      return EMPTY;  // complete silently — no error propagated
    })
  );

  // ── Handling errors in long-lived streams ─────────────────
  // WRONG: if the inner HTTP request errors, the entire search$ stream dies
  // searchBroken$ = searchInput$.pipe(
  //   switchMap(q => this.http.get(`/api/search?q=${q}`))
  // );

  // CORRECT: catch errors inside switchMap so the outer stream survives
  searchSafe$ = (searchInput$: any) => searchInput$.pipe(
    switchMap((q: string) =>
      this.http.get<any[]>(`/api/search?q=${q}`).pipe(
        catchError(err => {
          console.warn('Search failed:', err.status);
          return of([]);  // outer stream keeps running
        })
      )
    )
  );
}

import {
  Component, OnInit, OnDestroy, inject
} from '@angular/core';
import { AsyncPipe } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { toSignal } from '@angular/core/rxjs-interop';
import { Subscription, interval } from 'rxjs';
import { map } from 'rxjs/operators';

@Component({
  standalone: true,
  imports: [AsyncPipe],
  template: `
    <!-- ✓ async pipe: auto-subscribes and auto-unsubscribes -->
    <div>Posts: {{ posts$ | async | json }}</div>

    <!-- ✓ toSignal: auto-unsubscribes, readable as function call -->
    <div>Count: {{ tickCount() }}</div>

    <!-- ✓ takeUntilDestroyed: complete stream when component dies -->
    <div>Status: {{ status }}</div>
  `,
})
export class SubscriptionDemo implements OnInit, OnDestroy {
  private http = inject(HttpClient);

  // ── 1. async pipe — zero subscription management code ────
  posts$ = this.http.get<any[]>('/api/posts');

  // ── 2. toSignal — converts Observable to Signal, auto-cleans
  tickCount = toSignal(
    interval(1000).pipe(map(n => n + 1)),
    { initialValue: 0 }
  );

  // ── 3. takeUntilDestroyed() ───────────────────────────────
  status = 'waiting';

  constructor() {
    // Must be called inside injection context (constructor / field)
    interval(2000).pipe(
      takeUntilDestroyed()   // auto-completes when component is destroyed
    ).subscribe(() => {
      this.status = 'updated at ' + new Date().toLocaleTimeString();
    });
  }

  // ── 4. Manual Subscription (old style — avoid when possible)
  private clockSub!: Subscription;

  ngOnInit(): void {
    this.clockSub = interval(1000).subscribe(n => {
      // do something
    });
  }

  ngOnDestroy(): void {
    this.clockSub.unsubscribe();  // MUST remember to do this
  }

  // ── NEVER do this: no cleanup = memory leak ──────────────
  // ngOnInit() {
  //   interval(1000).subscribe(n => console.log(n));  // leaks forever!
  // }
}

import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { forkJoin, combineLatest, merge, of } from 'rxjs';
import { map, catchError } from 'rxjs/operators';

export class CombinationDemo {
  private http = inject(HttpClient);

  // ── forkJoin: run multiple Observables in parallel, wait for ALL
  // Like Promise.all() — emits one array when all complete
  // If ANY errors, the whole forkJoin errors
  loadDashboard$ = forkJoin({
    user:    this.http.get('/api/user'),
    posts:   this.http.get('/api/posts'),
    config:  this.http.get('/api/config'),
  }).pipe(
    catchError(err => of({ user: null, posts: [], config: null }))
  );
  // Result: { user: {...}, posts: [...], config: {...} }
  // emitted once when ALL three HTTP calls complete

  // ── combineLatest: emit when ANY source emits, with latest from all
  // Starts emitting only after ALL sources have emitted at least once
  // Great for combining user choices (filter + sort + page)
  filter$  = of('active');
  sort$    = of('name');
  page$    = of(1);

  filteredList$ = combineLatest({
    filter: this.filter$,
    sort:   this.sort$,
    page:   this.page$,
  }).pipe(
    map(({ filter, sort, page }) =>
      // fetch with combined params whenever any of them changes
      this.http.get(`/api/items?filter=${filter}&sort=${sort}&page=${page}`)
    )
  );

  // ── merge: combine multiple Observables, emit as values arrive
  // Like a funnel — values from any source flow through
  allEvents$ = merge(
    this.http.get('/api/events/a'),
    this.http.get('/api/events/b'),
    this.http.get('/api/events/c'),
  );
  // Values from all 3 requests arrive in the merged stream
  // as they complete — no waiting

  // ── shareReplay: multicast + cache for late subscribers ───
  // Without shareReplay: each subscriber makes its OWN HTTP call
  // With shareReplay(1): one call, result shared + cached for late subs
  sharedUser$ = this.http.get('/api/user').pipe(
    catchError(() => of(null)),
    // shareReplay(1)  // uncomment to cache the response
  );
}
